function calculateOnTimePercentage(partnerId) {
  // Simulate on-time rate based on ratings
  const partnerRatings = getRatingsForPartner(partnerId);
  if (partnerRatings.length === 0) return 95; // Default for new partners

  // Higher ratings correlate with on-time delivery
  const avgRating = calculateAverage(partnerRatings.map(r => r.ratings.delivery));
  return Math.min(99, Math.max(85, Math.round(avgRating * 20)));
}

