calculatePartnerScore(partner, order) {
    const distance = this.calculateDistance(partner.location, this.storeLocation);
    const distanceScore = Math.max(0, 1 - (distance / this.assignmentRules.maxDistance));

    const activeOrdersScore = Math.max(0, 1 - (partner.currentOrders / this.assignmentRules.maxConcurrentOrders));
    const waitTimeScore = partner.waitTime ? Math.max(0, 1 - (partner.waitTime / 3600000)) : 1;
    const ratingScore = (partner.rating || 4) / 5;

    return distanceScore * this.assignmentRules.weights.distance +
           activeOrdersScore * this.assignmentRules.weights.activeOrders +
           waitTimeScore * this.assignmentRules.weights.waitTime +
           ratingScore * this.assignmentRules.weights.rating;
}

