async function testEndpoint(endpoint, type) {
  try {
    const result = await makeRequest(endpoint.method, endpoint.path);
    const status = result.status >= 200 && result.status < 500 ? 'REACHABLE' : 'ERROR';
    console.log(`  ${status}: ${endpoint.method} ${endpoint.path} (${result.status})`);
    return { ...endpoint, status: result.status, reachable: true };
  } catch (err) {
    console.log(`  FAIL: ${endpoint.method} ${endpoint.path} - ${err.message}`);
    return { ...endpoint, error: err.message, reachable: false };
  }
}

